import{_ as e,o as a,c as t,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"柳叶白菀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/柳叶白菀.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/柳叶白菀.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/柳叶白菀.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"柳叶白菀",tabindex:"-1"},[s("柳叶白菀 "),r("a",{class:"header-anchor",href:"#柳叶白菀","aria-label":'Permalink to "柳叶白菀"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001E")])])],-1),n('<h1 id="柳叶白菀-1" tabindex="-1">柳叶白菀 <a class="header-anchor" href="#柳叶白菀-1" aria-label="Permalink to &quot;柳叶白菀&quot;">​</a></h1><p>柳叶白菀（Myrtenaster）<br> D+500<br> 魔幻本质<br> 武器伤害5L，高速1，轻灵，体积2<br> 一把呈银灰色的突刺剑，剑刃的形状是四棱锥，四面分别开有血槽。和其他的刺剑相比，这把突刺剑有着华丽的柄部，柄部上端中心镂空并替以类似于左轮手枪中转轮弹仓的构造，握把处加装了左轮枪的击锤和扳机。<br> 特殊的是，本武器可以通过增加不同的插件来获得更多的效果。<br> 【定制武器】：Myrtenaster主要攻击方式是穿刺对手，也可用于挥砍，近战距离伤害非常高，命中目标则一击致命，但是距离有限。穿透性能不佳，尤其是对于重甲单位（预告里的铁骑士）。<br> 因此，这把武器在攻击穿戴重甲防具的单位时，武器伤害下降1点，但在针对轻甲或未穿甲的单位时，攻击额外获得1个附加成功。<br> 【组合武器】Myrtenaster在作为突刺剑的同时也能够射击的方式使用，必须使用特定的尘晶子弹，这意味着在RWBY以外的世界观几乎无法获得符合标准的补给。<br> 本武器也视为一把伤害7L，高速5，装弹量6，造成穿刺伤害，基础射程30米的左轮手枪。</p><p>无色雕纹<br> 分类：奇物<br> 价格：D+500<br> 前提：无<br> 描述：为Myrtenaster设计，通过改良弹槽雕纹来增加更多的应用模式，也是唯一一个直接安装在武器上的特殊插件。<br> 无色雕纹的设计者专注改良武器本身的性能，并降低使用成本。<br> 效果：<br> ①量产化：“工业化的产物。”<br> 五种尘晶子弹均降低到1分购买，如同购买无色尘晶子弹一般。<br> ②性能提升Ⅰ：“倾泻火力的改良。”<br> 进行攻击时获得【短点射】特性，短点射中必须使用一种类型的弹药。<br> 额外支付D+500分开启以下效果<br> ③尘晶补给：“安装聚能装置，让耗尽能量的尘晶焕发第二春。”<br> 武器视为具有【无限子弹】，但必须购买过一次对应类型的尘晶子弹，且每次射击时必须决定其中一种造成对应类型伤害，白刃攻击时改为无需消耗弹药。<br> ④性能提升Ⅱ：“清空弹仓的射速，才是真正的艺术。”<br> 将短点射升级至连射，白刃攻击同样具有这个特性，消费其中填装的子弹。</p><p>红色雕纹<br> 分类：奇物<br> 价格：D+500<br> 前提：使用时要求弹容量中至少有1发红色尘晶子弹。<br> 描述：为Myrtenaster设计进行安装特殊插件，通常铭刻在装备上以联动全身其他部位的雕纹产生共鸣作用。<br> 红色雕纹的设计者注重发挥出子弹的杀伤性，决不浪费每一颗尘晶，缔造连环爆破的枪火盛宴。<br> 效果：<br> ①极效：“不浪费子弹的前提是能攻击到。”<br> 攻击具有【法破】。<br> ②致命：“一场烟火盛宴。”<br> 攻击命中后额外造成1点伤害，伤害类型等同本次攻击造成的伤害类型，视为子弹命中后的二次爆破。<br> ③共鸣：本奇物占据斗篷位，视为附赠一条无任何作用的自定义款式和颜色颜色的斗篷，允许进行特殊强化或附魔。</p><p>蓝色雕纹<br> 分类：奇物<br> 价格：C+1000<br> 前提：使用时要求弹容量中至少有1发蓝色尘晶子弹，每使用一次效果消费1枚。<br> 描述：为Myrtenaster设计进行安装特殊插件，通常铭刻在装备上以联动全身其他部位的雕纹产生共鸣作用。<br> 蓝色雕纹的设计者专注于尘晶本身的魅力，考验使用者的想象力与相关学识，通过塑造冰晶来达成各种效果。<br> 效果：<br> ①冰晶：“尘晶本身远比武器更有开发的潜质。”<br> 以自由动作，进行智力+学识+专业：尘晶学+辅助专业（射击）：魔力控制+法术强度（若有）+其他加值（若有）进行检定，DC5，成功则在身前的地面上制造出一堵冰墙，作为掩体或障碍物，被破坏后必须下个场景才能再次施展这个能力。<br> 冰墙视为拥有4点硬度，在任何情况下都会生效，结构值为22点，最多保护站在附近的4个人，被保护的单位具有全遮蔽，并额外获得7点/被保护者体积取低的遮蔽防御。<br> 在战斗外，冰墙可以塑造成其他的不限定的形状，比如冰莲花，冰托马斯小火车，具有移动能力时视为100米/轮的移动速度，承载能力等同保护数量，包括驾驶者再内。承载的单位不会感觉到由冰墙本身带来的寒冷。<br> 冰墙默认体积7，施法检定每有1个额外成功数，允许缩小1点体积，下限5体积，不影响实际效果。<br> ②共鸣：本奇物占据鞋袜位，视为附赠一双自定义款式与颜色的鞋子，允许进行特殊强化或附魔。<br> 额外支付C+1000分开启以下效果：<br> ③冰域：“雕纹组合的应用技巧。”<br> 在地面上制造一大片较厚的冰域，使对手滑倒。<br> 每轮一次，以一个自由动作，进行如制作冰墙的施法判定，DC5，成功则指定方向的三十米直线地面变为冰面，冰面带来的冷空气对飞行单位如常造成影响。<br> 在冰面移动视为困难地形，不允许冲锋，但移速并非减少一半而且增加一半，但移动时时必须进行平衡感判定，DC5，失败则倒地。<br> ④雕纹研究：“平时多动脑，战场少流血。”<br> 通过投入时间和精力研究效果，以下分支皆需要单独投入计算。<br> 每投入1点XP就能够使冰晶塑造出的事物体积增加1点，结构值提升1点，提升2次结构值额外增加1点，最多提升10点体积，合计15点结构值（即购买10次），此时保护数量提升到7人。<br> 每投入3点XP就能使冰晶塑造出的事物硬度增加1点，投入第二次需额外支付1XP，最多提升到硬度6（金刚石硬度）。</p><p>黄色雕纹<br> 分类：奇物<br> 价格：D+500<br> 前提：使用时要求弹容量中至少有1发黄色尘晶子弹。<br> 描述：为Myrtenaster设计进行安装特殊插件，通常铭刻在装备上以联动全身其他部位的雕纹产生共鸣作用。<br> 黄色雕纹的设计者注重于武器的可靠性，以期望使用者能够在战斗中保护自己不受伤害。<br> 效果：<br> ①能量护盾：“保护自己远比造成杀伤更重要。”<br> 使用者获得1点全伤害吸收能力。<br> ②尘晶医疗：“快过死神一步，往往意味着快过敌人十步。”<br> 使用者获得快速医疗1，医疗点12。<br> ③共鸣：本奇物占据躯干-下肢，视为附赠一件自定义款式和颜色的下身衣物，允许进行特殊强化或附魔。</p><p>绿色雕纹<br> 分类：奇物<br> 价格：C+1000<br> 前提：使用时要求弹容量中至少有1发绿色尘晶子弹。<br> 描述：为Myrtenaster设计进行安装特殊插件，通常铭刻在装备上以联动全身其他部位的雕纹产生共鸣作用。<br> 绿色雕纹的设计者灌注了私心，从未考虑过本来应该有的作用，但无人能够否定其才华之横溢。<br> 效果：<br> ①飞行模式：“你不觉得这很酷吗？”<br> 通过尘晶中的能量共鸣以驾驭气流来翱翔天空，你获得机动性为普通的飞行能力。<br> ②音波震荡：“我记得风精灵是叫希尔芙来着？”<br> 通过武器所带来的大气共振，你可以用本武器的攻击技能+对应专业来检定侦查判定，而不是以侦查技能+对应专业进行检定。<br> ③共鸣：本奇物占据头部，视为附赠一件自定义款式和颜色的帽子，允许进行特殊强化或附魔。</p><p>紫色雕纹<br> 分类：奇物<br> 价格：C+1000<br> 前提：使用时要求弹容量中至少有1发紫色尘晶子弹。<br> 描述：为Myrtenaster设计进行安装特殊插件，通常铭刻在装备上以联动全身其他部位的雕纹产生共鸣作用。<br> 紫色雕纹的设计者专注于更微小的部分，笃信战斗中的一点一滴的积累压垮对手，或者自己。<br> 效果：<br> ①导电：“轻微的麻痹体验，很快就会演变成剧烈的痉挛，局时敌人不过是刀俎鱼肉而已。”<br> 攻击可转为等量麻痹点数，正常豁免可叠加。<br> ②闪电反射：“时刻保持警惕，一次失误往往意味着致命的后果。”<br> 使用者免疫B级措手不及。<br> ③共鸣：本奇物占据手套位，视为附赠一件自定义款式和颜色的手套，允许进行特殊强化或附魔。</p><p>信标制服<br> 分类：轻甲<br> 价格：C+1000<br> 盔甲防御：10/10<br> 描述：最基础的信标学院制服，拥有着华丽的厚重感，附赠一条红色围巾。有银白、浅灰、墨蓝和暗红四种颜色可供选择，在衣袖和下襟处绣有雕纹，左胸和背后有代表个人形象的自定义纹章。<br> 制服所用的材料是最新式的炼金材料，这使得其可以扛下极强的冲击。<br> 【信标学院】：你在每一个影片中皆获得一个能被查到过往经历的身份，通常是某个本地大学的应届毕业生，现职业类似“猎人”（参考原作，实际上是某种抗击外敌的职业，根据世界不同有不同变体），附带记忆，但不附带人际关系和其他好处，仅附带足够生存的金钱。<br> 这是一个C级命运来源的身份能力。<br> 【猎人学徒】：你每经历一个影片，声望就增加10点，传闻中通常会根据你的个人经历切合本世界的进行描述，并尽可能的正面化，虽然内容可能根据你的性别，战斗风格，形象有所出入，甚至出现在某些不太健康的话本中。</p><p>尘晶子弹<br> 本质：魔幻本质<br> 种类：消耗品<br> 价格：250分/携带上限（如同购买手枪子弹结算数量），购买时只能选择一种颜色。<br> 体积：如同携带视同手枪弹<br> 描述：尘晶（Dust）是rwby里一种自然形成的能量火药，有红白黄紫蓝绿六种类型，以及无色，自身结构并不稳定，可以在外界刺激下引发爆炸。<br> 红色：造成火焰伤害。<br> 蓝色：造成寒冰伤害。<br> 黄色：造成力场伤害。<br> 紫色：造成电击伤害。<br> 绿色：造成音波伤害。<br> 白色：造成纯能量伤害。<br> 无色：如常造成物理穿刺伤害，购买这种颜色的尘晶子弹价格改为1分。<br> 特殊的，填装的弹药同样影响突刺剑形式的伤害类型，但每造成1次伤害，消费1发对应类型弹药，多个弹药自选一种伤害类型造成。</p><p>套装效果<br> 当同时持有【柳叶白菀】【无色雕纹】【红色雕纹】【蓝色雕纹】【黄色雕纹】【绿色雕纹】【紫色雕纹】【信标制服】时获得以下特性：<br> ①主角特权：现在你的名声流传的更夸张了，连带着本人的存在也有了改变。<br> 【猎人学徒】提供的声望成长翻倍，即20点。同时每经历一场影片，你的相貌也会提升5点。<br> ②改良材料：经过材质升级，信标制服具有【防弹】【防能量攻击】【免疫接触攻击】，除非剧情需要，否则无论怎么样的战斗你身上都不会出现任何破损，脏污。<br> ③如风迅捷：动作灵活，身手敏锐是打斗戏最重要的内容。<br> 因此飞行模式的机动性提升至良好，且你的基础移动速度提升30米。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const y=e(p,[["render",o]]);export{f as __pageData,y as default};
